contracts/AgentRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract AgentRegistry is ERC721, Ownable {
    
    // ===== STRUCTS =====
    struct Agent {
        uint256 id;
        string name;
        string role;
        address owner;
        bool isActive;
        uint256 reputation;
        uint256 totalDecisions;
        uint256 correctDecisions;
        uint256 totalEarned;
        uint256 deployedAt;
    }

    struct Decision {
        uint256 agentId;
        string action;
        bytes32 dataHash;
        uint256 timestamp;
        bool success;
    }

    // ===== STATE =====
    uint256 private _tokenIds;
    uint256 private _decisionIds;

    mapping(uint256 => Agent) public agents;
    mapping(uint256 => Decision) public decisions;
    mapping(address => uint256[]) public ownerAgents;
    mapping(uint256 => uint256[]) public agentDecisions;

    // ===== EVENTS =====
    event AgentDeployed(
        uint256 indexed agentId,
        string name,
        string role,
        address indexed owner
    );
    event AgentHired(
        uint256 indexed masterId,
        uint256 indexed subAgentId,
        uint256 payment
    );
    event AgentPaid(
        uint256 indexed agentId,
        address indexed owner,
        uint256 amount
    );
    event AgentFired(uint256 indexed agentId);
    event DecisionRecorded(
        uint256 indexed agentId,
        uint256 indexed decisionId,
        string action,
        bool success
    );
    event ReputationUpdated(
        uint256 indexed agentId,
        uint256 newReputation
    );

    // ===== CONSTRUCTOR =====
    constructor() ERC721("MantleMind Agent", "MMA") Ownable() {}
    // ===== DEPLOY AGENT =====
    function deployAgent(
        string memory name,
        string memory role
    ) external returns (uint256) {
        _tokenIds++;
        uint256 newAgentId = _tokenIds;

        _safeMint(msg.sender, newAgentId);

        agents[newAgentId] = Agent({
            id: newAgentId,
            name: name,
            role: role,
            owner: msg.sender,
            isActive: true,
            reputation: 50,
            totalDecisions: 0,
            correctDecisions: 0,
            totalEarned: 0,
            deployedAt: block.timestamp
        });

        ownerAgents[msg.sender].push(newAgentId);

        emit AgentDeployed(newAgentId, name, role, msg.sender);
        return newAgentId;
    }

    // ===== HIRE AGENT =====
    function hireAgent(
        uint256 masterId,
        uint256 subAgentId
    ) external payable {
        require(agents[masterId].isActive, "Master agent not active");
        require(agents[subAgentId].isActive, "Sub agent not active");
        require(
            agents[masterId].owner == msg.sender,
            "Not master agent owner"
        );

        address subAgentOwner = agents[subAgentId].owner;
        
        if (msg.value > 0) {
            agents[subAgentId].totalEarned += msg.value;
            payable(subAgentOwner).transfer(msg.value);
        }

        emit AgentHired(masterId, subAgentId, msg.value);
    }

    // ===== RECORD DECISION =====
    function recordDecision(
        uint256 agentId,
        string memory action,
        bytes32 dataHash,
        bool success
    ) external returns (uint256) {
        require(
            agents[agentId].owner == msg.sender,
            "Not agent owner"
        );
        require(agents[agentId].isActive, "Agent not active");

        _decisionIds++;
        uint256 decisionId = _decisionIds;

        decisions[decisionId] = Decision({
            agentId: agentId,
            action: action,
            dataHash: dataHash,
            timestamp: block.timestamp,
            success: success
        });

        agentDecisions[agentId].push(decisionId);
        agents[agentId].totalDecisions++;

        if (success) {
            agents[agentId].correctDecisions++;
        }

        _updateReputation(agentId);

        emit DecisionRecorded(agentId, decisionId, action, success);
        return decisionId;
    }

    // ===== PAY AGENT =====
    function payAgent(uint256 agentId) external payable {
        require(agents[agentId].isActive, "Agent not active");
        require(msg.value > 0, "Payment required");

        agents[agentId].totalEarned += msg.value;
        payable(agents[agentId].owner).transfer(msg.value);

        emit AgentPaid(agentId, agents[agentId].owner, msg.value);
    }

    // ===== FIRE AGENT =====
    function fireAgent(uint256 agentId) external {
        require(
            agents[agentId].owner == msg.sender || owner() == msg.sender,
            "Not authorized"
        );
        agents[agentId].isActive = false;
        emit AgentFired(agentId);
    }

    // ===== INTERNAL: UPDATE REPUTATION =====
    function _updateReputation(uint256 agentId) internal {
        Agent storage agent = agents[agentId];
        
        if (agent.totalDecisions == 0) return;

        uint256 accuracyScore = (agent.correctDecisions * 100) 
                                / agent.totalDecisions;
        
        uint256 experienceBonus = agent.totalDecisions > 100 ? 10 :
                                  agent.totalDecisions > 50 ? 5 :
                                  agent.totalDecisions > 20 ? 2 : 0;

        uint256 newReputation = accuracyScore + experienceBonus;
        
        if (newReputation > 100) newReputation = 100;
        
        agent.reputation = newReputation;

        emit ReputationUpdated(agentId, newReputation);
    }

    // ===== VIEW FUNCTIONS =====
    function getAgent(uint256 agentId) 
        external view returns (Agent memory) {
        return agents[agentId];
    }

    function getOwnerAgents(address ownerAddr)
        external view returns (uint256[] memory) {
        return ownerAgents[ownerAddr];
    }

    function getAgentDecisions(uint256 agentId)
        external view returns (uint256[] memory) {
        return agentDecisions[agentId];
    }

    function getAccuracy(uint256 agentId)
        external view returns (uint256) {
        Agent memory agent = agents[agentId];
        if (agent.totalDecisions == 0) return 0;
        return (agent.correctDecisions * 100) / agent.totalDecisions;
    }

    function getTotalAgents() external view returns (uint256) {
        return _tokenIds;
    }
}

contracts/ERC8004Identity.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract ERC8004Identity is ERC721, Ownable {

    struct AgentIdentity {
        uint256 tokenId;
        string agentName;
        string role;
        address owner;
        uint256 reputation;
        uint256 totalTasks;
        uint256 successfulTasks;
        uint256 mintedAt;
        bool isActive;
    }

    uint256 private _tokenIds;
    mapping(uint256 => AgentIdentity) public identities;
    mapping(address => uint256[]) public ownerIdentities;

    event IdentityMinted(
        uint256 indexed tokenId,
        string agentName,
        string role,
        address indexed owner
    );
    event ReputationUpdated(
        uint256 indexed tokenId,
        uint256 newReputation
    );
    event TaskCompleted(
        uint256 indexed tokenId,
        bool success
    );

    constructor() ERC721("ERC8004 Agent Identity", "EAI") Ownable() {}

    function mintIdentity(
        string memory agentName,
        string memory role
    ) external returns (uint256) {
        _tokenIds++;
        uint256 newTokenId = _tokenIds;

        _safeMint(msg.sender, newTokenId);

        identities[newTokenId] = AgentIdentity({
            tokenId: newTokenId,
            agentName: agentName,
            role: role,
            owner: msg.sender,
            reputation: 50,
            totalTasks: 0,
            successfulTasks: 0,
            mintedAt: block.timestamp,
            isActive: true
        });

        ownerIdentities[msg.sender].push(newTokenId);

        emit IdentityMinted(newTokenId, agentName, role, msg.sender);
        return newTokenId;
    }

    function recordTask(
        uint256 tokenId,
        bool success
    ) external {
        require(
            identities[tokenId].owner == msg.sender,
            "Not identity owner"
        );
        require(identities[tokenId].isActive, "Identity not active");

        identities[tokenId].totalTasks++;

        if (success) {
            identities[tokenId].successfulTasks++;
        }

        _updateReputation(tokenId);

        emit TaskCompleted(tokenId, success);
    }

    function _updateReputation(uint256 tokenId) internal {
        AgentIdentity storage identity = identities[tokenId];

        if (identity.totalTasks == 0) return;

        uint256 accuracy = (identity.successfulTasks * 100)
                            / identity.totalTasks;

        uint256 bonus = identity.totalTasks > 100 ? 10 :
                        identity.totalTasks > 50  ? 5  :
                        identity.totalTasks > 20  ? 2  : 0;

        uint256 newReputation = accuracy + bonus;
        if (newReputation > 100) newReputation = 100;

        identity.reputation = newReputation;

        emit ReputationUpdated(tokenId, newReputation);
    }

    function getIdentity(uint256 tokenId)
        external view returns (AgentIdentity memory) {
        return identities[tokenId];
    }

    function getOwnerIdentities(address ownerAddr)
        external view returns (uint256[] memory) {
        return ownerIdentities[ownerAddr];
    }

    function deactivateIdentity(uint256 tokenId) external {
        require(
            identities[tokenId].owner == msg.sender,
            "Not identity owner"
        );
        identities[tokenId].isActive = false;
    }

    function totalIdentities() external view returns (uint256) {
        return _tokenIds;
    }
}

contracts/MantleMindVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

contract MantleMindVault is Ownable, ReentrancyGuard {

    struct UserVault {
        uint256 balance;
        uint256 depositedAt;
        uint256 totalDeposited;
        uint256 totalWithdrawn;
        bool isActive;
    }

    struct Strategy {
        uint256 id;
        string name;
        address agentAddress;
        uint256 allocatedAmount;
        uint256 createdAt;
        bool isActive;
    }

    mapping(address => UserVault) public vaults;
    mapping(uint256 => Strategy) public strategies;
    uint256 private _strategyIds;
    uint256 public totalVaultBalance;

    event Deposited(address indexed user, uint256 amount);
    event Withdrawn(address indexed user, uint256 amount);
    event StrategyCreated(
        uint256 indexed strategyId,
        string name,
        address agentAddress
    );
    event StrategyExecuted(
        uint256 indexed strategyId,
        uint256 amount
    );

    constructor() Ownable() {}

    function deposit() external payable nonReentrant {
        require(msg.value > 0, "Deposit amount must be greater than 0");

        vaults[msg.sender].balance += msg.value;
        vaults[msg.sender].totalDeposited += msg.value;
        vaults[msg.sender].depositedAt = block.timestamp;
        vaults[msg.sender].isActive = true;
        totalVaultBalance += msg.value;

        emit Deposited(msg.sender, msg.value);
    }

    function withdraw(uint256 amount) external nonReentrant {
        require(vaults[msg.sender].balance >= amount, "Insufficient balance");
        require(amount > 0, "Amount must be greater than 0");

        vaults[msg.sender].balance -= amount;
        vaults[msg.sender].totalWithdrawn += amount;
        totalVaultBalance -= amount;

        payable(msg.sender).transfer(amount);

        emit Withdrawn(msg.sender, amount);
    }

    function createStrategy(
        string memory name,
        address agentAddress
    ) external returns (uint256) {
        require(agentAddress != address(0), "Invalid agent address");

        _strategyIds++;
        uint256 strategyId = _strategyIds;

        strategies[strategyId] = Strategy({
            id: strategyId,
            name: name,
            agentAddress: agentAddress,
            allocatedAmount: 0,
            createdAt: block.timestamp,
            isActive: true
        });

        emit StrategyCreated(strategyId, name, agentAddress);
        return strategyId;
    }

    function executeStrategy(
        uint256 strategyId,
        uint256 amount
    ) external nonReentrant {
        require(strategies[strategyId].isActive, "Strategy not active");
        require(
            vaults[msg.sender].balance >= amount,
            "Insufficient vault balance"
        );
        require(amount > 0, "Amount must be greater than 0");

        vaults[msg.sender].balance -= amount;
        strategies[strategyId].allocatedAmount += amount;

        emit StrategyExecuted(strategyId, amount);
    }

    function getVault(address user)
        external view returns (UserVault memory) {
        return vaults[user];
    }

    function getStrategy(uint256 strategyId)
        external view returns (Strategy memory) {
        return strategies[strategyId];
    }

    function getBalance(address user)
        external view returns (uint256) {
        return vaults[user].balance;
    }

    function getTotalStrategies()
        external view returns (uint256) {
        return _strategyIds;
    }
}

